// Step gate: each contact's schedule is keyed to THEIR OWN confirmed
// prior-step delivery, not a fixed cohort date. Overdue throttling:
// capped per run, drained gradually -- never one burst.

const fs = require('fs');
const path = require('path');

const PER_RUN_CAP = 80;
const SEQUENCE = ['E1', 'E2', 'E3', 'E4'];

let allContacts = [];
const projectDirs = fs.readdirSync('Working', { withFileTypes: true }).filter(d => d.isDirectory());
for (const d of projectDirs) {
  try {
    const contacts = JSON.parse(fs.readFileSync(path.join('Working', d.name, 'contacts.json'), 'utf8'));
    for (const c of contacts) if (c.valid_format) allContacts.push({ ...c, project_prefix: d.name });
  } catch (e) {}
}

let sendLog = {};
try { sendLog = JSON.parse(fs.readFileSync(path.join('Shared', 'send_log.json'), 'utf8')); } catch (e) {}

const due = [];
const now = Date.now();

for (const c of allContacts) {
  const key = c.project_prefix + ':' + c.email;
  const history = sendLog[key] || {};
  let nextStep = null;

  for (let i = 0; i < SEQUENCE.length; i++) {
    const step = SEQUENCE[i];
    if (history[step] && history[step].confirmed) continue;
    if (i === 0) { nextStep = step; break; }
    const prevStep = SEQUENCE[i - 1];
    const prevConfirmed = history[prevStep] && history[prevStep].confirmed;
    if (prevConfirmed && (now - new Date(history[prevStep].confirmed_at).getTime()) >= 24 * 60 * 60 * 1000) {
      nextStep = step;
    }
    break;
  }

  if (nextStep) due.push({ ...c, next_step: nextStep, key });
}

// Overdue throttling -- cap per run, drain gradually across runs.
const thisRun = due.slice(0, PER_RUN_CAP);
return thisRun.map(d => ({ json: d }));

// Deadline check (A8): no pre-submission email (E1-E4) fires after
// the due date, checked before every send, same place the DNC check
// sits.
const fs = require('fs');
const path = require('path');
let doc;
try { doc = JSON.parse(fs.readFileSync(path.join('Working', $json.project_prefix, 'project_document.json'), 'utf8')); } catch (e) {}
const expired = doc && doc.deadline && doc.deadline.due_date_parsed && new Date(doc.deadline.due_date_parsed).getTime() < Date.now();
return [{ json: { ...$json, expired } }];

// Conversion check: UNBUFFERED, LIVE, immediately pre-send -- never a
// batch-load cache. Reads status fresh from disk right here, right now,
// not from the list built at run-start (fixes the throttled-batch
// staleness race).

const fs = require('fs');
const path = require('path');

let intakeLog = [];
try { intakeLog = JSON.parse(fs.readFileSync(path.join('Shared', 'intake_log.json'), 'utf8')); } catch (e) {}

const live = intakeLog.find(e => e.project_prefix === $json.project_prefix && e.email === $json.email);
const alreadyConverted = live && ['nda_signed', 'payment_confirmed'].includes(live.status);

// E4 specifically targets non-NDA holdouts only, by design -- an
// NDA-signed contact is correctly excluded here regardless of paid
// status; their path is the Follow-up Watcher's payment-drop reminder.
const skip = $json.next_step === 'E4' ? (live && live.status !== undefined) : alreadyConverted;

return [{ json: { ...$json, skip_send: !!skip } }];

// Correction-queue check: before every send, checks the AI-corrected
// contact overlay first; used in place of the original if present.
const fs = require('fs');
const path = require('path');
let corrections = [];
try { corrections = JSON.parse(fs.readFileSync(path.join('Working', $json.project_prefix, 'ai_corrected_contacts.json'), 'utf8')); } catch (e) {}
const match = corrections.find(c => c.original_email === $json.email);
return [{ json: { ...$json, send_to_email: match ? match.corrected_email : $json.email } }];

// Global DNC check: fs.statSync, size (primary) + mtimeMs (secondary)
// against last-seen. Either changing triggers a re-read. Checked
// before every single send.

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const dncPath = path.join('Shared', 'global_dnc.txt');
const stat = fs.statSync(dncPath);

const staticData = $getWorkflowStaticData('global');
const changed = staticData.dnc_size !== stat.size || staticData.dnc_mtime !== stat.mtimeMs;

if (changed || !staticData.dnc_set) {
  const lines = fs.readFileSync(dncPath, 'utf8').split('\n').filter(Boolean);
  staticData.dnc_set = lines;
  staticData.dnc_size = stat.size;
  staticData.dnc_mtime = stat.mtimeMs;
}

const normalized = String($json.send_to_email).toLowerCase().trim().replace(/\+.*@/, '@');
const hash = crypto.createHash('sha256').update(normalized).digest('hex');
const suppressed = staticData.dnc_set.includes(hash);

return [{ json: { ...$json, dnc_suppressed: suppressed } }];

const fs = require('fs');
const path = require('path');
let sendLog = {};
try { sendLog = JSON.parse(fs.readFileSync(path.join('Shared', 'send_log.json'), 'utf8')); } catch (e) {}
if (!sendLog[$json.key]) sendLog[$json.key] = {};
sendLog[$json.key][$json.next_step] = { sent_at: new Date().toISOString(), confirmed: false };
fs.writeFileSync(path.join('Shared', 'send_log.json'), JSON.stringify(sendLog, null, 2), 'utf8');
return [{ json: $json }];
